var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아…","JPN":"わあ……","ENG":"Wow...","TWN":"哇……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"말랑말랑- 복슬복슬-","JPN":"ふわふわ～もこもこ～","ENG":"So soft... So fluffy...","TWN":"軟綿綿——毛茸茸——"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"끄응.","JPN":"ぐうっ。","ENG":"Ugh.","TWN":"呃。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"귀는 그만하면 충분히 만지지 않았냐?","JPN":"耳はもう十分触ったでしょ？","ENG":"Haven't you touched my ears enough?","TWN":"耳朵摸夠了沒有啊？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 죄송해요! 치료만 해드린다는 게 그만 신기해서…","JPN":"あっ、すみません！　治療するつもりが、不思議でつい……","ENG":"Oh, I'm sorry! I meant to treat you, but your ears were so mesmerizing...","TWN":"啊，對不起！只是想包紮一下，結果因為太神奇了……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데- 별님들은 다들 그런 멋진 귀와 꼬리를 가지고 있는 건가요?","JPN":"あの、お星さまって皆そんな素敵な耳と尻尾をお持ちなんですか？","ENG":"Just wondering, but... do all stars have such pretty ears and tails?","TWN":"但是～星星們都有那樣漂亮的耳朵和尾巴嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"난 별님이 아니라 패러독스다. 그리고 이 꼬리는 환상토의 선조 대대로 물려받아온…","JPN":"私はお星さまじゃなくてパラドックスだよ。そしてこの尻尾は幻想土の先祖から受け継いだ……","ENG":"I'm not a star. My name is Paradox. And this tail has been passed down for generations from my ancestors in Byrwood–","TWN":"我不是星星，我叫悖論！而且這條尾巴是我的幻想種祖先代代相傳的……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼 패리라고 불러도 되죠?","JPN":"じゃあ、パリーって呼んでもいいんですよね？","ENG":"Then, may I call you Parry?","TWN":"那我可以叫你悖悖嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 녀석, 내 말은 듣지도 않고 아주 제멋대로구만.","JPN":"あんた、私の話はこれっぽっちも聞いてないんだね。","ENG":"Ugh, you're not even listening to a word I'm saying.","TWN":"你這傢伙，完全不聽我的話，真是任性。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어… 화났어요?","JPN":"えっと……怒ってますか？","ENG":"Oh... are you mad at me?","TWN":"呃……你生氣了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"서로 주고 받는 대화는 정말 오랜만이라서…","JPN":"人と話すのはすごく久しぶりで……","ENG":"It's been a long time since I had a proper conversation with anyone...","TWN":"我好久沒有這樣和別人說話了……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"미안해요. 이제 말 안 할게요.","JPN":"ごめんなさい。もう喋りません。","ENG":"I'm sorry. I won't talk anymore.","TWN":"對不，。我會捂住嘴巴的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"여기서 너 혼자 얼마나 지낸 거야?","JPN":"ここでどれぐらい1人で過ごしたの？","ENG":"How long have you been here alone?","TWN":"你一個人在這裡住了多久？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"읍…? 음읍읍?","JPN":"うぶ……？　うっぶぶ……？","ENG":"Mm...? Mm mmph mmph?","TWN":"唔……？嗯唔唔？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"끙… 누가 입 틀어 막고 있으래? 말해도 되니까 손 치워.","JPN":"ぐう……何も口を塞げとは言ってないでしょう。喋っていいから。","ENG":"Ngh... No one told you to cover your mouth! You can talk, so take your hand off.","TWN":"呃……誰叫你捂住嘴巴的？可以說話了，快把手拿開。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"파하-!","JPN":"ぷは～！","ENG":"Paha–!","TWN":"啪哈——！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"음, 어머니가 가르쳐주신 셈대로라면… 생일 다섯 번 동안 혼자 보냈어요.","JPN":"うーん……お母さんに教えてもらったとおりに数えると……誕生日が5回過ぎる間、1人で過ごしました。","ENG":"Mm, from what Mother taught me... I've been alone for five birthdays.","TWN":"嗯，如果按照媽媽教我的方法……我已經獨自過了五個生日了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"마침 내일이 제 여섯번째 생일이거든요. 적어도 이번엔 혼자 보내지 않겠네요!","JPN":"ちょうど明日が私の6回目の誕生日なんです。今年の誕生日は1人じゃなくて嬉しいな！","ENG":"And tomorrow is my sixth. And I won't have to spend it alone!","TWN":"正好明天是第六個。至少這次不會一個人過了呢！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"토마토 좋아해요? 좀 덜 익긴 했지만 맛있을 거예요! 지난 번에 살구도 잔뜩 땄어요!","JPN":"トマトは好きですか？　まだ完熟ではないけどおいしいはずです！　この前は杏の実もたくさん採れました！","ENG":"Do you like tomatoes? They might not be ripe yet, but they're still delicious! I even picked a lot of apricots the other day!","TWN":"你喜歡蕃茄嗎？雖然有點不太熟，但一定很好吃！上次我還摘了很多杏子呢！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"미안하지만 난 여기 놀러온 게 아니다.","JPN":"悪いけど、私はここに遊びに来たわけじゃないの。","ENG":"I'm sorry, but I didn't come here to have fun.","TWN":"對不起，我不是來這裡玩的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼요. 알고 말고요.","JPN":"はい、わかってます。","ENG":"Of course. I know that.","TWN":"當然，我知道。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어떤 사람의 소원을 들어주러 내려온 거죠?","JPN":"誰かの願いを叶えるために来たんですね？","ENG":"You came down to grant someone their wish, right?","TWN":"你是來實現某個人的願望的吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"소원이라… 아주 틀린 얘긴 아니군.","JPN":"願い……間違ってはないね。","ENG":"A wish...? Well, you're not wrong.","TWN":"願望啊……這麼說也不是完全不對。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"관리국이 네 어머니에게 맡겨둔 걸 가지러 왔어.","JPN":"管理局があなたのお母さんに預けていたものを、取りに来たんだ。","ENG":"I'm here to retrieve what the Administration left your mother.","TWN":"我來取一件管理局託付給你媽媽的東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"위치가 바뀐 게 아니라면, 아마도 이 정원의 중심부에 있겠지.","JPN":"場所が変わってないなら、おそらくこの庭園の中心部にあるはず。","ENG":"If the location hasn't changed, it should still be at the center of the garden.","TWN":"如果位置沒有改變的話，應該就在這個花園的中心。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"관리국…?! 그럼 당신이 관리국의 영웅이었군요!","JPN":"管理局……！？　じゃああなたは管理局の英雄だったんですね！","ENG":"The Administration...?! Then you must be the hero of the Administration!","TWN":"管理局……？！那你就是管理局的英雄了！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"영웅… 이라고?","JPN":"英雄……？","ENG":"Hero...?","TWN":"英雄……是這樣嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마요! 제가 정원 안으로 안내해줄게요!","JPN":"心配要りません！　私が庭園の中までご案内します！","ENG":"Don't worry! I'll guide you into the garden!","TWN":"別擔心！我會帶你進入花園的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네가…?","JPN":"あなたが？","ENG":"You...?","TWN":"你……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니한테 들었어요.","JPN":"お母さんから聞きました。","ENG":"Mother told me once.","TWN":"媽媽說。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"세계가 위기에 처했을 때 관리국의 영웅들이 나타나서 저희를 구해줬다고요.","JPN":"世界が危機に陥った時、管理局の英雄が現れて私たちを助けてくれたって。","ENG":"That when the world was in crisis, the heroes of the Administration appeared and saved us.","TWN":"當世界陷入危機時，是管理局的英雄們出現並拯救了我們。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래서 그 답례로 우리가 관리국의 보물을 지키는 거랬어요. 언젠가 그 영웅분들이 오면 돌려주려고요.","JPN":"だからそのお礼に、私たちが管理局のお宝を守るのだそうです。いつか英雄の方々が来たら、返してあげるために。","ENG":"And in return, we protect the Administration's treasure. So that when they come back one day, we can return it to them.","TWN":"所以作為回報，我們負責守護管理局的寶物。等那些英雄們有一天回來時，我們會還給他們。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"난 영웅이 아니야. 굳이 따지자면 조언자 정도라고 해두지.","JPN":"私は英雄じゃないよ。敢えて言うなら、助言者かな。","ENG":"I'm not a hero. Let's just say that I'm an advisor.","TWN":"我不是英雄。硬要說的話，充其量算是個顧問吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"조언자? 그럼 조언자는 영웅이 아닌가요?","JPN":"助言者？　助言者は英雄とは違うのですか？","ENG":"An advisor? Then, are advisors not heroes?","TWN":"顧問？那顧問不是英雄嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아… 하긴 영웅은 정원 밖에서 세계를 구하느라 바쁘다고 들었어요. 이런 곳까지 올 여유도 없겠네요.","JPN":"あ……そういえば、英雄は庭園の外で世界を救うため忙しく働いていると聞きました。多分、ここに来る暇はありませんね。","ENG":"Oh... I see. I also heard that heroes are busy protecting the world outside of the garden. I guess they don't have the time to come here.","TWN":"啊……也是，聽說英雄們都忙著在外面拯救世界，哪有時間來這種地方……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래서 어머니도 함께 따라가지 못한 거래요. 절 뱃속에 품고 있으면, 바쁜 영웅들한테 방해가 될 수 있으니까요.","JPN":"だからお母さんも英雄たちと一緒には行けなかったみたいです。お腹に私がいると、他の英雄たちの邪魔になるから。","ENG":"That's why Mother couldn't go along with them. With me in her belly, she thought she'd be a hindrance to the busy heroes.","TWN":"所以媽媽也沒能一起去！如果懷著我，會妨礙到忙碌的英雄們。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"자아-","JPN":"はい、できました。","ENG":"Okay...","TWN":"好啦——"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 하면 피도 멎고 상처도 덧나지 않을 거예요.","JPN":"こうすれば血も止まるし、傷が開くこともありませんよ。","ENG":"Now, the bleeding should stop and your wound will heal quickly.","TWN":"這樣做的話，血也會止住，傷口也不會惡化。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"예쁘게 리본 모양으로 묶었는데, 예쁘죠? 어머니한테 배웠거든요.","JPN":"リボン結び、可愛いでしょう？　お母さんに教えてもらったんです。","ENG":"I even tied it in a pretty ribbon shape. Isn't it pretty? I learned it from Mother.","TWN":"我把它打成了漂亮的蝴蝶結，很漂亮吧？這是我從媽媽那裡學來的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…그래. 예쁘구나.","JPN":"……そう、可愛いね。","ENG":"...Yes, it is pretty.","TWN":"……嗯。很美呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"너무 걱정 말아요.","JPN":"大丈夫ですよ。","ENG":"Don't worry.","TWN":"別擔心。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 보물은 제가 책임지고 돌려줄 테니까요.","JPN":"管理局のお宝は、責任を持って私がお返しします。","ENG":"I'll make sure to return the Administration's treasure.","TWN":"管理局的寶物就由我來負責歸還吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"꽃차는 어때요? 향기롭죠? 맘에 드나요?","JPN":"花茶はどうですか？　いい香りでしょう？　気に入ってもらえましたか？","ENG":"What do you think of the flower tea? Isn't it fragrant? Do you like it?","TWN":"花茶怎麼樣？很香吧？喜歡嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"음… 맛은 그냥 물 맛인데… 향이 과일처럼 달콤하네.","JPN":"うーん……味はただのお湯だけど……香りは果物みたいに甘いんだね。","ENG":"Mm... It just tastes like water... but the scent is sweet, like a fruit.","TWN":"嗯……嚐起來像水一樣……但香氣卻像水果一樣甜美。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"어째 익숙한 향이기도 하고.","JPN":"どこかで嗅いだ気がする香り。","ENG":"It also smells familiar.","TWN":"而且有種熟悉的味道。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아! 역시 어머니의 동료라면 알 줄 알았어요!","JPN":"わあ！　お母さんの仲間ならわかってくれると思いました！","ENG":"Wow! I knew Mother's friends would notice!","TWN":"哇啊！果然是媽媽的同伴，你果然知道啊！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이건 금잔화라는 꽃으로 만든 차에요. 어머니 곁엔 항상 이런 향기가 났거든요.","JPN":"これはキンセンカという花で作ったお茶です。お母さんからはいつもこんな香りがしたんです。","ENG":"This is tea made from a flower called Calendula.","TWN":"這是用金盞花做的茶。媽媽身邊總是有這種香氣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니가 떠나신 뒤론… 더 이상 정원에 자라지 않는 꽃이 됐지만요.","JPN":"お母さんが去ってからは……庭園でこの花が育つことはなくなりましたけど。","ENG":"But after Mother left... there's no Calendula in the garden anymore.","TWN":"只是媽媽離開後……花園裡的花就再也不會綻放了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 왜 너만 여기 두고 떠난 거야?","JPN":"パブリンはなんであなた1人だけここに残したの？","ENG":"Why did Pavlin leave you alone here?","TWN":"帕芙琳為什麼只留下你一個人？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그야 어머니는 어른이니까요. 모험을 떠나는 건 당연한 거죠.","JPN":"お母さんは大人ですから。冒険に出るのは当たり前です。","ENG":"That's because Mother is an adult. It's natural that she goes on adventures.","TWN":"那是因為媽媽是大人啊。去冒險是理所當然的事。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어른들은 평생 자식만 돌볼 정도로 한가롭지 않잖아요. 항상 책임을 갖고 살아야 하니까요.","JPN":"大人たちって、ずっと子どもの世話ができるほど暇じゃないでしょう？　色んな責任を背負ってますし。","ENG":"Adults are busy and cannot take care of their children forever. They must always be responsible.","TWN":"大人們可沒那麼閒，能一輩子照顧孩子。因為他們總是要肩負責任嘛。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 어른은 아니지만 그 정돈 이해할 수 있다구요.","JPN":"私は大人じゃないけど、それぐらいはわかります。","ENG":"I may not be an adult, but I understand that much.","TWN":"雖然我不是大人，但那點事我還是能理解的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"6년이 되도록 돌아오지 않는데 걱정되지 않아?","JPN":"6年経っても帰ってこないのに、心配じゃないの？","ENG":"She hasn't been back for 6 years. Doesn't that concern you?","TWN":"都已經6年了還沒回來，你不擔心嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"당연히 걱정되죠!","JPN":"もちろん心配ですよ！","ENG":"Of course, it concerns me!","TWN":"當然會擔心啊……！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만… 약속했어요. 어머닐 대신해 제가 이 정원을 가꾸기로요.","JPN":"でも……約束したんです。お母さんに代わって、この庭園は私が管理するって。","ENG":"But... I made a promise. That I'll take care of the garden instead of her.","TWN":"可是……我答應了媽媽。要代替她來打理這個花園。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 어머니 걱정에 빠져서 정원을 소홀히 해두면, 분명 돌아오셨을 때 실망할 거예요.","JPN":"心配ばかりして手入れを疎かにすれば、お母さんが帰ってきた時きっとがっかりします。","ENG":"If I neglect the garden out of concern for Mother, she'll be disappointed when she returns.","TWN":"如果我因為擔心她而疏忽了打理花園，媽媽回來時一定會失望的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…그렇구나.","JPN":"……そっか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"솔로베는 책임감이 강하네.","JPN":"ソロベーは責任感が強いんだね。","ENG":"You have a strong sense of responsibility, Solovey.","TWN":"蘇羅薇也很有責任感呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래야죠. 전 하루라도 더 빨리 어른이 되고 싶으니까요.","JPN":"もちろんです。私は一日でも早く大人になりたいですから。","ENG":"I must. Because I want to become an adult as fast as possible.","TWN":"當然了。我可是想儘快長成大人呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리는 어머니랑 아는 사이니까, 어른이죠?","JPN":"お母さんの知り合いなら、パリーも大人ですよね？","ENG":"You're an adult too because you're friends with Mother, aren't you, Parry?","TWN":"悖悖是媽媽認識的人，所以是大人吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 그렇지?","JPN":"まあ、そうだね。","ENG":"Yeah, I guess?","TWN":"嗯，是的？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"흐음, 어른인데도 저랑 키가 비슷하네요.","JPN":"ふーん……なのに、背は私と変わらないんですね。","ENG":"Hmm. You're an adult, but you're as tall as me.","TWN":"嗯，明明是大人，卻和我差不多高呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 당연히 어머니처럼 큰 어른이 될 줄 알았는데, 여기서 안 자랄 수도 있나 보네요.","JPN":"私も、お母さんみたいに大きくなれると思ってたけど……もしかしたらこれ以上背が伸びない可能性もあるんですね。","ENG":"I thought that I'd become a tall adult like Mother when I grow up, but I guess I could stop growing at this height.","TWN":"我本來以為自己會長得和媽媽一樣高，但現在看來沒辦法長大了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니가 돌아오면 더 큰 옷을 만드는 법을 배우려 했는데, 괜한 걱정이었나 봐요.","JPN":"お母さんが帰ってきたら、もっと大きい服を作る方法を教えてもらうつもりだったのに、その必要はないかもしれません。","ENG":"I planned on learning how to make bigger clothes when Mother returned, but I guess I worried for nothing.","TWN":"等媽媽回來後，我還計畫著做更大件的衣服，看來想多了呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"걱정 마. 넌 아직 한창 더 클 테니.","JPN":"心配ないよ。あなたはまだ大きくなれる。","ENG":"Don't worry. You're still growing.","TWN":"不用擔心，你還會繼續長高的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"사람마다 다른 법이지만, 그래도 유전이라는 게 있으니까.","JPN":"人によるけど、遺伝ってものがあるからね。","ENG":"It's different for each person, but genetics still count.","TWN":"每個人都不一樣，但畢竟有遺傳基因在。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"유전…? 그게 뭐죠?","JPN":"遺伝……？　それは何ですか？","ENG":"Genetics...? What's that?","TWN":"遺傳……？那是什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"부모와 자식은 보통 닮는다는 얘기야. 성격도, 모습도…","JPN":"親と子供は似るって意味だよ。性格も、外見も……","ENG":"It means that children and their parents usually look alike. In both personality and appearance...","TWN":"意思是孩子通常長得像父母。性格也好，外貌也好……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그렇구나.","JPN":"そうなんですね。","ENG":"Okay.","TWN":"原來是這樣呀。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"유전이란 건 좋네요! 전 항상 어머니를 닮고 싶었거든요.","JPN":"遺伝っていいですね！　私、いつもお母さんみたいになりたいと思ってたんです。","ENG":"I like genetics! I've always wanted to be like Mother!","TWN":"遺傳基因真是個好東西！我一直想成為媽媽那樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하지만 얼마나 닮을지는 네가 노력하기 나름이다.","JPN":"でも、どこまで似るかはあなた次第だよ。","ENG":"But, that will depend on how much effort you put in.","TWN":"但能有多像，就看你的努力了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"유전만 믿고 네가 밥을 잘 안 챙겨 먹거나 늦잠만 자면, 나처럼 키 작은 어른이 될지도?","JPN":"遺伝に頼って、ちゃんと食事を摂らなかったり、寝坊ばかりしたりしたら私みたいに背の低い大人になるかも。","ENG":"If you don't eat well and oversleep, while relying solely on genetics, you might become a short adult like me.","TWN":"如果只靠遺傳，不好好吃飯或者總是熬夜還睡懶覺，可能會像我一樣長不高喔？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 안녕히 주무세요.","JPN":"あっ、おやすみなさい。","ENG":"Oh. Goodnight, then.","TWN":"啊，那麼晚安～"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데, 키가 작아도 괜찮을 것 같아요. 패리는 귀여우니까요.","JPN":"でも、背は伸びなくてもいい気がします。パリーはかわいいですから。","ENG":"Still, I don't think being small is that bad. You're cute, Parry.","TWN":"不過，我覺得個子矮也沒關係。悖悖很可愛嘛。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"쓸데없는 소리 말고 자라.","JPN":"もういいから、寝なさい。","ENG":"Stop talking nonsense and go to bed.","TWN":"少廢話，快點睡覺。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내일 아침이 되면 네가 길안내를 해줘야 하니까.","JPN":"明日の朝になったら、あなたに道案内をしてもらわないと。","ENG":"You're going to have to be my guide tomorrow morning.","TWN":"明天早上你還得帶路呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저는요. 패리가 와서 기뻐요.","JPN":"私、パリーが来て嬉しいです。","ENG":"You know. I'm glad you're here, Parry.","TWN":"我很高興悖悖來了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니는 제가 어른이 되기 전엔 안뜰로 들어오면 안된다고 그랬거든요.","JPN":"大人になるまで中庭に入ってはいけないと、お母さんに言われていました。","ENG":"Mother said that I wasn't allowed to enter the inner yard until I became an adult.","TWN":"媽媽說在我長大成人之前，不可以進入內院。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 패리는 어른이니까. 어른이랑 함께라면 저도 안뜰로 들어가도 될 거예요.","JPN":"でもパリーは大人だし、大人と一緒なら私も中庭に入っていいはずです。","ENG":"But since you're an adult, I should be able to enter it with you.","TWN":"但悖悖是大人。如果和大人在一起的話，我也可以進入內院。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 모험 중인 어머니와 마주치게 될지도 몰라요. 저희를 보면 분명 깜짝 놀라시겠죠?","JPN":"もしかしたら、冒険中のお母さんに出会えるかも。私たちを見たらきっとびっくりするでしょうね。","ENG":"I might even bump into Mother on her adventure. I'm sure she'll be so surprised to see us, right?","TWN":"說不定會在冒險中遇到媽媽呢。看到我們，她一定會大吃一驚吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그 보물은 어떻게 생긴 거예요? 어머니는 저한테 한 번도 보여준 적 없거든요.","JPN":"宝物って、どんな形なのですか？　お母さんは一度も見せてはくれませんでした。","ENG":"What does this treasure look like? Mother never showed it to me once.","TWN":"那個寶物是什麼樣的？媽媽從來沒有給我看過。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"참! 영웅분들은 어떻게 생겼나요? 어머니보다 키가 큰 분도 있어요?","JPN":"そうだ！　英雄の方々はどんな顔をしていますか？　お母さんより背が高い人もいるのですか？","ENG":"Oh! And what do the heroes look like? Is there anyone taller than Mother?","TWN":"對了！英雄們長什麼樣子？有比媽媽還高的人嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니의 스승님은 검을 엄청 잘 휘두른대요. 그런데 검을 직접 본 적은 없어요.","JPN":"お母さんの師匠は剣術の腕がすごいと聞きました。でも私、剣を見たことがないんです。","ENG":"I heard Mother's master was skilled with a sword. But I've never seen a sword in person before.","TWN":"聽說媽媽的師父很會耍劍。但是我從來沒見過她。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"나중에 저도 휘둘러봐도 돼요?","JPN":"後で振ってみてもいいですか？","ENG":"Could I swing it a few times later?","TWN":"以後我也可以試著揮劍嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그렇게 안 자고 말 많이 하면 키 줄어든다.","JPN":"早く寝なさい。ずっと喋ってると、背が縮むよ。","ENG":"You're not going to grow if you keep talking and don't go to bed.","TWN":"不睡覺還說那麼多話，會長不高的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"코오-","JPN":"すや……","ENG":"Zzz...","TWN":"Zzz——"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 공간은 파블린의 격리 능력으로 만들어낸 장소다.","JPN":"この空間は、パブリンの隔離能力で作り出した場所だ。","ENG":"This place was made by Pavlin's isolation ability.","TWN":"這個空間是由帕芙琳的隔離能力創造的地方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"세계와 분리된 이곳에선 영원히 시간이 흐르지 않는 게 정상일 터.","JPN":"世界と分離したこの空間では、時間は永遠に止まっている。","ENG":"Being separated from the world, time should be suspended forever in here.","TWN":"在這個與世隔絕的地方，正常來講，時間是永遠不會流逝的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"시간이 흐른다는 건 격리에 문제가 생겼다는 뜻이겠지.","JPN":"でも今こうして時間が流れているということは、隔離に問題が生じた証拠だ。","ENG":"Seeing how time is flowing, it could only mean that there's a problem with the isolation.","TWN":"正因如此，說明隔離出現了問題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"끙, 역시 일이 순탄치 않겠군. 무슨 일이 있어도 발키리 녀석만은 데려오려고 했는데.","JPN":"ぐぬぬ……やっぱり上手くはいかないな。何があってもヴァルキリーのやつだけは連れて行くつもりだったのに。","ENG":"Ugh, I knew this wouldn't go as smoothly as I thought it would. I wanted to at least bring Valkyrie with me no matter what.","TWN":"唉……果然不會順利。要是女武神還在身邊就好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그 녀석이 그리 쉽게 죽진 않겠지만… 지금쯤 어찌 됐으려나.","JPN":"あいつがそう簡単に死ぬはずないけど……今頃どうしているんだろ……","ENG":"I know she wouldn't die that easily, but... I wonder what happened to her.","TWN":"那傢伙雖然不會那麼容易死……但她現在到底怎麼樣了嘛……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};